// Generate a random value and store it
var a = GD.Randf() + GD.Randi();

// Reset the seed to the same value
GD.Seed(mySeed);

// Generate the random value again
var b = GD.Randf() + GD.Randi();

GD.Print(a);  // Outputs a random value
GD.Print(b);  // Outputs the same random value as 'a'

