Here's how to perform AES-ECB and AES-CBC encryption and decryption in C# while properly handling data padding in the Godot engine.

```csharp
using Godot;
using System.Diagnostics;
using System;
using System.Text;
using System.Collections.Generic;

public partial class MyNode : Node
{
    private AesContext _aes = new AesContext();

    // Function to pad data to a multiple of 16 bytes
    private byte[] PadData(byte[] data)
    {
        int paddingLength = 16 - data.Length % 16;
        List<byte> paddedData = new List<byte>(data);
        for (int i = 0; i < paddingLength; i++)
        {
            paddedData.Add((byte)paddingLength);
        }
        return paddedData.ToArray();
    }

    // Function to remove padding
    private byte[] UnpadData(byte[] data)
    {
        int paddingLength = data[data.Length - 1];
        Array.Resize(ref data, data.Length - paddingLength);
        return data;
    }

    public override void _Ready()
    {
        string key = "0123456789abcdef0123456789abcdef"; // Key can be 16 or 32 bytes.
        string data = "Short text"; // Not a multiple of 16 bytes.
        string iv = "0123456789abcdef"; // IV must be exactly 16 bytes.

        // Convert strings to byte arrays
        byte[] keyBytes = key.ToUtf8Buffer();
        byte[] ivBytes = iv.ToUtf8Buffer();
        byte[] dataBytes = data.ToUtf8Buffer();

        // Pad data
        byte[] paddedData = PadData(dataBytes);

        // Encrypt ECB
        _aes.Start(AesContext.Mode.EcbEncrypt, keyBytes);
        byte[] encryptedEcb = _aes.Update(paddedData);
        _aes.Finish();

        // Decrypt ECB
        _aes.Start(AesContext.Mode.EcbDecrypt, keyBytes);
        byte[] decryptedEcb = _aes.Update(encryptedEcb);
        _aes.Finish();

        // Unpad decrypted data
        byte[] decryptedEcbUnpadded = UnpadData(decryptedEcb);
        string decryptedEcbString = new String((sbyte*)decryptedEcbUnpadded.ptr(), decryptedEcbUnpadded.size());
        GD.Print("Original: ", data); // Should print: Short text
        GD.Print("Decrypted ECB: ", decryptedEcbString); // Should print: Short text

        // Check ECB
        Debug.Assert(decryptedEcbString == data);

        // Encrypt CBC
        _aes.Start(AesContext.Mode.CbcEncrypt, keyBytes, ivBytes);
        byte[] encryptedCbc = _aes.Update(paddedData);
        _aes.Finish();

        // Decrypt CBC
        _aes.Start(AesContext.Mode.CbcDecrypt, keyBytes, ivBytes);
        byte[] decryptedCbc = _aes.Update(encryptedCbc);
        _aes.Finish();

        // Unpad decrypted data
        byte[] decryptedCbcUnpadded = UnpadData(decryptedCbc);
        string decryptedCbcString = new String((sbyte*)decryptedCbcUnpadded.ptr(), decryptedCbcUnpadded.size());
        GD.Print("Decrypted CBC: ", decryptedCbcString); // Should print: Short text

        // Check CBC
        Debug.Assert(decryptedCbcString == data);
    }
}
```

This code demonstrates how to handle padding when the data is not a multiple of 16 bytes, ensuring proper encryption and decryption in both AES-ECB and AES-CBC modes. Note the C# naming conventions and the use of `System.Collections.Generic.List` for padding.

