public void SetupAStarGrid()
{
    var astar = new AStar2D();

    // Create a 3x3 grid of points with some weights
    for (int x = 0; x < 3; x++)
    {
        for (int y = 0; y < 3; y++)
        {
            int id = x + (y * 3); // Unique ID for each point
            astar.AddPoint(id, new Vector2(x, y), 1); // Default weight is 1
        }
    }

    // Connect points horizontally and vertically (no diagonal)
    for (int x = 0; x < 3; x++)
    {
        for (int y = 0; y < 3; y++)
        {
            int id = x + (y * 3);
            if (x < 2) astar.ConnectPoints(id, id + 1, false); // Right
            if (y < 2) astar.ConnectPoints(id, id + 3, false); // Down
        }
    }

    // Change weight for a specific connection
    astar.ConnectPoints(3, 4, true); // Connect point 3 to 4, making it harder to go through
    // Now find paths
    long[] path1 = astar.GetIdPath(0, 8); // Should find a path to bottom right
    long[] path2 = astar.GetIdPath(8, 0); // Should also find a path albeit via a different route

    // Output all found paths
    GD.Print("Path from 0 to 8: " + String.Join(", ", path1));
    GD.Print("Path from 8 to 0: " + String.Join(", ", path2));
}
