```csharp
using Godot;
using System;

public partial class MyAStar : AStar3D
{
    public override float _ComputeCost(long fromId, long toId)
    {
        // Returns the Euclidean distance as cost
        var fromPoint = GetPointPosition(fromId);
        var toPoint = GetPointPosition(toId);
        return fromPoint.DistanceTo(toPoint);
    }

    public override float _EstimateCost(long fromId, long toId)
    {
        // Using Euclidean distance as an estimate
        return _ComputeCost(fromId, toId);
    }
}

public class AStarPathfindingSystem : Node
{
    private MyAStar _astar;

    public override void _Ready()
    {
        _astar = new MyAStar();
        AddChild(_astar);

        // Adding points
        var idA = _astar.AddPoint(new Vector3(0, 0, 0));
        var idB = _astar.AddPoint(new Vector3(5, 0, 3));
        var idC = _astar.AddPoint(new Vector3(3, 5, 1));
        var idD = _astar.AddPoint(new Vector3(8, 4, 2));

        // Connecting points
        _astar.ConnectPoints(idA, idB);
        _astar.ConnectPoints(idB, idC);
        _astar.ConnectPoints(idC, idD);
        _astar.ConnectPoints(idA, idC);
        _astar.ConnectPoints(idA, idD);

        // Finding path
        var pathIds = _astar.GetIdPath(idA, idD);
        GD.Print("Best path indices: ", pathIds);

        // Getting actual path coordinates
        var pathPoints = _astar.GetPointPath(idA, idD);
        GD.Print("Best path coordinates: ", pathPoints);
    }
}
```

