```csharp
public AudioStreamMP3 LoadMP3Streamed(string path)
{
    // Initialize an AudioStreamMP3 for streaming
    var stream = new AudioStreamMP3();
    try
    {
        using var file = FileAccess.Open(path, FileAccess.ModeFlags.Read);
        // Load only necessary chunks of data
        while (file.GetPosition() < file.GetLength())
        {
            var chunk = file.GetBuffer(Math.Min(1024 * 1024, file.GetLength() - file.GetPosition())); // Load 1MB at a time
            stream.Data = chunk;
            // Process the audio data...
        }
    }
    catch (Exception e)
    {
        GD.PrintErr("Error loading audio file in chunks: " + e.Message);
    }
    return stream;
}
```  
