In C#, you can create a class that defines how to multiply a Vector3 by a custom Basis using operator overloading:

```csharp
using Godot;

public class CustomBasis
{
    private Vector3 xBasis;
    private Vector3 yBasis;
    private Vector3 zBasis;

    public CustomBasis(Vector3 x, Vector3 y, Vector3 z)
    {
        xBasis = x;
        yBasis = y;
        zBasis = z;
    }

    public static Vector3 operator *(CustomBasis basis, Vector3 vector)
    {
        return new Vector3(
            basis.xBasis.x * vector.x + basis.yBasis.x * vector.y + basis.zBasis.x * vector.z,
            basis.xBasis.y * vector.x + basis.yBasis.y * vector.y + basis.zBasis.y * vector.z,
            basis.xBasis.z * vector.x + basis.yBasis.z * vector.y + basis.zBasis.z * vector.z
        );
    }
}

// Usage example:
var myBasis = new CustomBasis(new Vector3(0, 2, 0), new Vector3(2, 0, 0), new Vector3(0, 0, 2));
var result = myBasis * new Vector3(1, 2, 3);
GD.Print(result); // Will print (4, 2, 6)
```
