```csharp
public class ColorUtility
{
    public static void PrintRgba64(Color color)
    {
        if (!IsColorValid(color))
        {
            GD.PrintErr("Invalid color values. Must be between 0 and 1.");
            return;
        }

        // Convert color to RGBA64
        var rgba64 = color.ToRgba64();
        GD.Print(rgba64); // Prints the RGBA64 representation of the color
    }

    private static bool IsColorValid(Color color)
    {
        return (color.r >= 0 && color.r <= 1 && 
                color.g >= 0 && color.g <= 1 && 
                color.b >= 0 && color.b <= 1 && 
                color.a >= 0 && color.a <= 1);
    }
}

