```gdscript
class_name ThemeManager
extends Node

var overrides: Dictionary = {}

func add_color_override(control_name: String, color_name: String, color_value: Color) -> void:
    # Store override information.
    if not overrides.has(control_name):
        overrides[control_name] = {}
    overrides[control_name][color_name] = color_value

    # Apply the color override to the control.
    var control = get_node(control_name)
    if control:
        control.add_theme_color_override(color_name, color_value)
        GD.Print("Color override added for %s: %s" % [control_name, color_name])
    else:
