```csharp
public class FocusController : Control
{
    private List<Control> controls = new List<Control>();

    public override void _Ready()
    {
        // Assuming controls are added to this child node
        foreach (Control control in GetChildren())
        {
            controls.Add(control);
        }
    }

    public override void _Process(double delta)
    {
        if (Input.IsActionJustPressed("ui_select")) // Assume 'ui_select' is a defined action
        {
            SwapFocus();
        }
    }

    private void SwapFocus()
    {
        // Simple round-robin focus swap
        foreach (Control control in controls)
        {
            if (control.HasFocus())
            {
                control.GrabClickFocus(); // Re-focus the current control
                GD.Print(control.Name + " focused.");
                return;
            }
        }
    }
}
