void RecursiveMerge(Dictionary target, Dictionary source, bool overwrite)
{
    foreach (var key in source.Keys)
    {
        if (target.Contains(key) && !overwrite)
            continue; // Skip if we don't want to overwrite

        if (source[key] is Dictionary sourceDict && target[key] is Dictionary targetDict)
        {
            // If both values are dictionaries, merge recursively
            RecursiveMerge(targetDict, sourceDict, overwrite);
        }
        else
        {
            // Otherwise, set the value directly
            target[key] = source[key];
        }
    }
}

