Here's a basic example of a DTLS server in Godot using GDScript:

```gdscript
# server_node.gd
extends Node

var dtls := DTLSServer.new()
var server := UDPServer.new()
var peers = []

func _ready():
    server.listen(4242)  # Start listening on port 4242
    var key = load("key.key")  # Load your private key
    var cert = load("cert.crt")  # Load your X509 certificate
    dtls.setup(key, cert)  # Setup the DTLS server

func _process(delta):
    while server.is_connection_available():
        var peer: PacketPeerUDP = server.take_connection()  # Accept a new UDP connection
        var dtls_peer: PacketPeerDTLS = dtls.take_connection(peer)  # Wrap it with DTLS
        if dtls_peer.get_status() != PacketPeerDTLS.STATUS_HANDSHAKING:
            continue  # Skip if not handshaking, failure is expected
        print("Peer connected!")
        peers.append(dtls_peer)  # Add connected peer to the list

    for p in peers:
        p.poll()  # Poll all connected peers
        if p.get_status() == PacketPeerDTLS.STATUS_CONNECTED:
            while p.get_available_packet_count() > 0:
                print("Received message from client: %s" % p.get_packet().get_string_from_utf8())  # Print received messages
                p.put_packet("Hello DTLS client".to_utf8_buffer())  # Respond to client
```  
This code sets up a server that listens for DTLS connections, accepts them, and interacts with connected clients by sending and receiving messages.

