Here's an advanced DTLS server example that is designed to handle multiple clients:

```gdscript
# multi_client_server.gd
extends Node

var dtls := DTLSServer.new()
var server := UDPServer.new()
var peers = []

func _ready():
    if server.listen(4242) == OK:
        var key = load("key.key")  # Load your private key
        var cert = load("cert.crt")  # Load your X509 certificate
        dtls.setup(key, cert)
    else:
        print_err("Failed to start server on port 4242.")

func _process(delta):
    while server.is_connection_available():
        var peer: PacketPeerUDP = server.take_connection()  # Accept a new UDP connection
        var dtls_peer: PacketPeerDTLS = dtls.take_connection(peer)  # Wrap it with DTLS
        if dtls_peer.get_status() != PacketPeerDTLS.STATUS_HANDSHAKING:
            print_err("Connection failed for client.")  # Log failed connections
            continue
        print("Peer connected!")
        peers.append(dtls_peer)

    # Poll each peer's state in a thread-safe manner
    for p in peers:
        if p.is_connected():
            p.poll()  # Poll connected peers
            if p.get_status() == PacketPeerDTLS.STATUS_CONNECTED:
                while p.get_available_packet_count() > 0:
                    print("Received message from client: %s" % p.get_packet().get_string_from_utf8())  # Print incoming messages
                    p.put_packet("Hello DTLS client".to_utf8_buffer())  # Respond to each client
    # Remove disconnected peers
    peers = [peer for peer in peers if peer.is_connected()]
