{
    using var f = FileAccess.Open("user://file.dat", FileAccess.ModeFlags.WriteRead);

    // Attempt to store a negative value, which will wrap around
    f.Store16(unchecked((ushort)-42)); // This results in overflow, storing 65494

    // Store a valid value
