    // Seek back to the beginning of the file to read back the stored values
    f.Seek(0);
    ushort read1 = f.Get16(); // This reads 65494
    ushort read2 = f.Get16(); // This reads 121

    // Convert back to signed short for correct interpretation
    short converted1 = (short)read1; // -42
    short converted2 = (short)read2; // 121

