public class NodeConnectionValidator : MonoBehaviour
{
    // List of node IDs that represent already visited nodes
    private HashSet<StringName> visitedNodes = new HashSet<StringName>();

    public override bool _IsNodeHoverValid(StringName fromNode, int fromPort, StringName toNode, int toPort)
