Here's an advanced implementation of a message authentication system using HMACContext:

```csharp
using Godot;
using System;
using System.Diagnostics;

public partial class AuthenticationManager : Node
{
    private HmacContext _ctx;
    private byte[] _key;

    public AuthenticationManager(string key)
    {
        _key = key.ToUtf8Buffer();
        _ctx = new HmacContext();
    }

    public byte[] GenerateHMAC(byte[] message)
    {
        _ctx.Start(HashingContext.HashType.Sha256, _key);
        _ctx.Update(message);
        return _ctx.Finish();
    }

    public bool VerifyMessage(byte[] message, byte[] receivedHMAC)
    {
        byte[] calculatedHMAC = GenerateHMAC(message);
        return receivedHMAC.SequenceEqual(calculatedHMAC);
    }
}

