    public override bool _Process(double delta)
    {
        _timeElapsed += delta;
        // Return true to end the main loop if the mouse is clicked or escape is pressed.
        return Input.GetMouseButtonMask() != 0 || Input.IsKeyPressed(Key.Escape);
    }

    private void _Finalize()
    {
        GD.Print("Finalized:");
        GD.Print($"  End Time: {_timeElapsed}");
    }
}
```

This class initializes the elapsed time when the game starts, updates the time in the _Process method, and allows exiting the loop based on user input (mouse click or pressing the Escape key). Note the use of global class attribute to register it in the project.

