```csharp
public Array GetNodeAndResource(NodePath path)
{
    // Use GetNode to fetch the requested node
    var node = GetNode(path);

    // Prepare result array
    Array result = new Array();
    result.Add(node);

    if (node != null)
    {
        // Check for nested resource
        Resource resource = null;
        string[] pathParts = path.ToString().Split(':');
        if (pathParts.Length > 1)
        {
            var lastPart = pathParts[pathParts.Length - 1];
            var resourcePath = path.Replace($":{lastPart}", "");
            resource = node.GetResource(resourcePath);
            result.Add(resource);
            result.Add(lastPart);
        }
        else
        {
            result.Add(null);
            result.Add(path);
        }
    }
    else
    {
        result.Add(null); // Node not found
        result.Add(null); // Resource also null
        result.Add(path);
    }

    return result;
}

