    if not packer.pck_start(package_name):
        GD.PrintErr("Failed to start creating package.")
        return false

    for file in files:
        if not packer.add_file(file.source, file.destination):
            GD.PrintErr("Could not add: %s" % file.source)
            return false

    packer.flush()  # Finalize the package
    return true

func load_package(package_name: String) -> void:
    if ProjectSettings.load_resource_pack(package_name):
        GD.Print("Package loaded: %s" % package_name)
    else:
        GD.PrintErr("Failed to load package: %s" % package_name)

# Usage example:
var files_to_pack = [{"source":"res://data/file1.txt", "destination":"file1.txt"}, {"source":"res://data/image.png", "destination":"image.png"}]
if create_package("example.pck", files_to_pack):
    load_package("example.pck")
``` 

