public class InertiaManager : Node
{
    private RigidBody3D _rigidBody;

    public override void _Ready()
    {
        _rigidBody = GetNode<RigidBody3D>("Ball");
        UpdateInertia();
    }

    private void UpdateInertia()
    {
        // Automatically compute inertia based on attached shapes
        if (_rigidBody.Inertia == Vector3.Zero)
        {
            // Retrieve computed inertia
