Here's a C# implementation of an RSplit utility function:

```csharp
using System;
using System.Collections.Generic;

public static class StringUtil
{
    public static List<string> RSplit(string input, string delimiter = "", bool allowEmpty = true, int maxsplit = 0)
    {
        List<string> results = new List<string>();
        if (string.IsNullOrEmpty(input)) return results;

        string[] splits = input.Split(new string[] { delimiter }, StringSplitOptions.None);
        int count = splits.Length;  

        if (maxsplit > 0 && maxsplit < count) count = maxsplit + 1;

        for (int i = splits.Length - 1; i >= splits.Length - count; i--)
        {
            if (allowEmpty || !string.IsNullOrEmpty(splits[i]))
            {
                results.Add(splits[i]);
            }
        }
        results.Reverse();
        return results;
    }
}

// Usage example:
var result = StringUtil.RSplit("apple,banana,,cherry,", ",", false);
// result: ["apple", "banana", "cherry"]
```

This function replicates the behavior of RSplit by splitting a string from the end with options for limiting the splits and handling empty substrings.

