Here is an advanced example of a UDP server handling multiple clients with error handling:

```csharp
// AdvancedServerNode.cs
using Godot;
using System.Collections.Generic;

public partial class AdvancedServerNode : Node
{
    private UdpServer _server = new UdpServer();
    private List<PacketPeerUdp> _peers = new List<PacketPeerUdp>();

    public override void _Ready()
    {
        _server.Listen(4242); // Start server
    }

    public override void _Process(double delta)
    {
        _server.Poll(); // Process incoming packets
        while (_server.IsConnectionAvailable())
        {
            PacketPeerUdp peer = _server.TakeConnection();
            if (peer != null)
            {
                byte[] packet = peer.GetPacket();
                HandlePacket(peer, packet);
            }
        }
    }

    private void HandlePacket(PacketPeerUdp peer, byte[] packet)
    {
        if (packet.Length == 0)
        {
            GD.PrintErr("Received empty packet from " + peer.GetPacketIP());
            return; // Ignore empty packets
        }

        string message = packet.GetStringFromUtf8();
        GD.Print($"Received message: {message} from {peer.GetPacketIP()}:{peer.GetPacketPort()}");

        // Reply to peer
        peer.PutPacket(packet); // Echo the packet back
        if (!_peers.Contains(peer))
        {
            _peers.Add(peer); // Track the peer
        }
    }
}
```

In this implementation, the server processes incoming packets and checks for empty packets to avoid errors. It echoes received messages back and handles multiple clients effectively.

Here’s a tutorial example for creating a simple chat system in Godot using UDP:

```csharp
// ChatServer.cs
using Godot;
using System.Collections.Generic;

public partial class ChatServer : Node
{
    private UdpServer _server = new UdpServer();
    private List<PacketPeerUdp> _clients = new List<PacketPeerUdp>();

    public override void _Ready()
    {
        _server.Listen(4242); // Listen on port 4242
        GD.Print("Chat server started");
    }

    public override void _Process(double delta)
    {
        _server.Poll(); // Process incoming connections
        while (_server.IsConnectionAvailable())
        {
            PacketPeerUdp peer = _server.TakeConnection();
            if (peer != null)
            {
                byte[] packet = peer.GetPacket();
                HandleClientMessage(peer, packet);
            }
        }
    }

    private void HandleClientMessage(PacketPeerUdp peer, byte[] packet)
    {
        if (packet.Length > 0)
        {
            string message = packet.GetStringFromUtf8();
            GD.Print($"Received message: {message} from {peer.GetPacketIP()}:{peer.GetPacketPort()}");

            // Echo back the message to all connected clients
            foreach (var client in _clients)
            {
                if (client != peer) // Avoid sending it back to the sender
                {
                    client.PutPacket(packet);
                }
            }
            if (!_clients.Contains(peer)){
                _clients.Add(peer);
            }
        }
        else
        {
            GD.PrintErr("Empty packet received, ignoring.");
        }
    }
}

// ChatClient.cs
using Godot;

public partial class ChatClient : Node
{
    private PacketPeerUdp _udp = new PacketPeerUdp();
    private string _username = "User";

    public override void _Ready()
    {
        _udp.ConnectToHost("127.0.0.1", 4242); // Connect to server
    }

    public override void _Process(double delta)
    {
        if (Input.IsActionJustPressed("send_message"))
        {
            string message = Input.GetActionStrength("message_input").ToString();
            if (!string.IsNullOrEmpty(message))
            {
                _udp.PutPacket(("[" + _username + "]: " + message).ToUtf8Buffer());
            }
        }

        if (_udp.GetAvailablePacketCount() > 0)
        {
            GD.Print($"Received from server: {_udp.GetPacket().GetStringFromUtf8()}");
        }
    }
}
```

In the code above, the `ChatServer` listens for incoming messages and broadcasts them to all connected clients, while the `ChatClient` sends messages based on user input. This example includes checks for empty packets and handles connections in a straightforward way.

