Here's a GDScript example of a WebSocket client:

```gdscript
extends Node

var socket = WebSocketPeer.new()

func _ready():
    # Connect to the WebSocket server
    socket.connect_to_url("wss://example.com")

func _process(delta):
    # Poll for incoming packets
    socket.poll()

    var state = socket.get_ready_state()
    if state == WebSocketPeer.STATE_OPEN:
        while socket.get_available_packet_count():
            print("Packet: ", socket.get_packet())
    elif state == WebSocketPeer.STATE_CLOSING:
        # Keep polling during closing
        pass
    elif state == WebSocketPeer.STATE_CLOSED:
        var code = socket.get_close_code()
        var reason = socket.get_close_reason()
        print("WebSocket closed with code: %d, reason %s. Clean: %s" % [code, reason, code != -1])
        set_process(false)  # Stop processing.
```

This example establishes a connection to a WebSocket server and continuously polls for messages, printing them when received. It also handles closing states appropriately.

Here’s an advanced example of a WebSocket client with error handling and reconnect logic:

```gdscript
extends Node

var socket = WebSocketPeer.new()
var reconnect_attempts = 0
var max_reconnects = 5

func _ready():
    connect_to_server()

func connect_to_server():
    socket.connect_to_url("wss://example.com")
    reconnect_attempts += 1
    GD.Print("Attempting to connect... Attempt " + str(reconnect_attempts))

func _process(delta):
    socket.poll()
    var state = socket.get_ready_state()

    if state == WebSocketPeer.STATE_OPEN:
        while socket.get_available_packet_count():
            print("Packet: ", socket.get_packet())
    elif state == WebSocketPeer.STATE_CLOSING:
        pass
    elif state == WebSocketPeer.STATE_CLOSED:
        handle_disconnect()

func handle_disconnect():
    if reconnect_attempts < max_reconnects:
        GD.Print("Disconnected. Attempting to reconnect...")
        yield(get_tree().create_timer(2.0), "timeout")  # Wait 2s before reconnecting
        connect_to_server()
    else:
        GD.Print("Max reconnect attempts reached. Giving up.")
        set_process(false)  # Stop processing.
```

This code attempts to reconnect a predefined number of times if the WebSocket connection fails, and provides user feedback along the way.

Here's how to send a text message via a WebSocket client and handle the response:

```gdscript
extends Node

var socket = WebSocketPeer.new()

func _ready():
    socket.connect_to_url("wss://example.com")
    send_message("Hello WebSocket!")  # Send a message after connecting

func _process(delta):
    socket.poll()
    var state = socket.get_ready_state()

    if state == WebSocketPeer.STATE_OPEN:
        while socket.get_available_packet_count():
            var packet = socket.get_packet()
            print("Received: ", packet)
    elif state == WebSocketPeer.STATE_CLOSED:
        handle_close()

func send_message(message: String):
    if socket.get_ready_state() == WebSocketPeer.STATE_OPEN:
        socket.send(message)
        print("Sent: ", message)
    else:
        print("Cannot send message, WebSocket not open.")

func handle_close():
    var code = socket.get_close_code()
    var reason = socket.get_close_reason()
    print("WebSocket closed with code: %d, reason: %s" % [code, reason])
    set_process(false)  # Stop processing.
```

In this example, the `send_message` function sends a text message if the WebSocket is currently open, and incoming messages are printed as they are received.

