            uvs.append(Vector2(u, v))
            point += 1
            if i > 0 and j > 0:
                indices.append((prevrow + j - 1))
                indices.append((prevrow + j))
                indices.append((thisrow + j - 1))
                indices.append((prevrow + j))
                indices.append((thisrow + j))
                indices.append((thisrow + j - 1))
